 95→func (h *Handler) dispatch(req Request) (Response, bool) {
 96→	base := Response{
 97→		ProtocolVersion: ProtocolVersion,
 98→		ID:              req.ID,
 99→	}
100→
101→	if req.ProtocolVersion != ProtocolVersion {
102→		base.Status = "error"
103→		base.Code = ErrVersionMismatch
104→		base.Message = fmt.Sprintf(
105→			"unsupported protocol version %q, expected %q",
106→			req.ProtocolVersion, ProtocolVersion,
107→		)
108→		return base, false
109→	}
110→
111→	switch req.Command {
112→	case "handshake":
113→		return h.handleHandshake(base, req), false
114→	case "analyze":
115→		return h.handleAnalyze(base, req), false
116→	case "instrument":
117→		return h.handleInstrument(base, req), false
118→	case "execute":
119→		return h.handleExecute(base, req), false
120→	case "setup":
121→		return h.handleSetup(base, req), false
122→	case "teardown":
123→		return h.handleTeardown(base, req), false
124→	case "generate":
125→		return h.handleGenerate(base, req), false
126→	case "shutdown":
127→		return h.handleShutdown(base), true
128→	default:
129→		base.Status = "error"
130→		base.Code = ErrInvalidRequest
131→		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
132→		return base, false
133→	}
134→}
