231→func (h *Handler) handleExecute(resp Response, req Request) Response {
232→	file := req.File
233→	if file == "" {
234→		file = h.lastAnalyzedFile
235→	}
236→	if file == "" {
237→		resp.Status = "error"
238→		resp.Code = ErrInvalidRequest
239→		resp.Message = "execute command requires a file path (or a prior analyze)"
240→		return resp
241→	}
242→
243→	if req.Function == nil || *req.Function == "" {
244→		resp.Status = "error"
245→		resp.Code = ErrInvalidRequest
246→		resp.Message = "execute command requires a function name"
247→		return resp
248→	}
249→
250→	if _, err := os.Stat(file); err != nil {
251→		resp.Status = "error"
252→		resp.Code = ErrFileNotFound
253→		resp.Message = fmt.Sprintf("file not found: %s", file)
254→		return resp
255→	}
256→
257→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
258→	var execMocks []instrument.MockConfig
259→	for _, m := range req.Mocks {
260→		execMocks = append(execMocks, instrument.MockConfig{
261→			Symbol:           m.Symbol,
262→			ReturnValues:     m.ReturnValues,
263→			ShouldTrackCalls: m.ShouldTrackCalls,
264→			DefaultBehavior:  m.DefaultBehavior,
265→		})
266→	}
267→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
268→	if err != nil {
269→		resp.Status = "error"
270→		if strings.Contains(err.Error(), "function not found") {
271→			resp.Code = "function_not_found"
272→		} else if strings.Contains(err.Error(), "build failed") {
273→			resp.Code = "instrumentation_failed"
274→		} else if strings.Contains(err.Error(), "timed out") {
275→			resp.Code = ErrExecutionTimeout
276→		} else {
277→			resp.Code = ErrInternalError
278→		}
279→		resp.Message = err.Error()
280→		return resp
281→	}
282→
283→	resp.Status = "execute"
284→	resp.ReturnValue = result.ReturnValue
285→	resp.ThrownError = convertErrorInfo(result.ThrownError)
286→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
287→	resp.BranchPath = convertBranchPath(result.BranchPath)
288→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
289→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
290→	resp.SideEffects = convertSideEffects(result.SideEffects)
291→	resp.ScopeEvents = result.ScopeEvents
292→	resp.Performance = &PerfMetrics{
293→		WallTimeMs:         result.Performance.WallTimeMs,
294→		CPUTimeUs:          result.Performance.CPUTimeUs,
295→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
296→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
297→	}
298→
299→	return resp
300→}
