324→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
325→	result := make([]BranchDecision, len(branches))
326→	for i, b := range branches {
327→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
328→		if b.ConstraintJSON != "" {
329→			var sc SymConstraint
330→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
331→				constraint = &sc
332→			}
333→		}
334→		result[i] = BranchDecision{
335→			BranchID:   b.BranchID,
336→			Line:       b.Line,
337→			Taken:      b.Taken,
338→			Constraint: constraint,
339→		}
340→	}
341→	return result
342→}
343→
344→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
345→	var constraints []SymConstraint
346→	for _, b := range branches {
347→		if b.ConstraintJSON == "" {
348→			continue
349→		}
350→		var sc SymConstraint
351→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
352→			constraints = append(constraints, sc)
353→		}
354→	}
355→	if constraints == nil {
356→		return []SymConstraint{}
357→	}
358→	return constraints
359→}
