456→func (h *Handler) handleTeardown(resp Response, req Request) Response {
457→	if req.Scope == "" {
458→		resp.Status = "error"
459→		resp.Code = ErrInvalidRequest
460→		resp.Message = "teardown command requires a scope"
461→		return resp
462→	}
463→	if !req.Level.IsValid() {
464→		resp.Status = "error"
465→		resp.Code = ErrInvalidRequest
466→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
467→		return resp
468→	}
469→
470→	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)
471→
472→	h.setupLoader.Teardown(req.Scope, string(req.Level))
473→
474→	resp.Status = "teardown_ack"
475→	return resp
476→}
