529→func (h *Handler) send(resp Response) error {
530→	data, err := json.Marshal(resp)
531→	if err != nil {
532→		return fmt.Errorf("marshaling response: %w", err)
533→	}
534→	line := string(data) + "\n"
535→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
536→	_, err = io.WriteString(h.writer, line)
537→	return err
538→}
